Code.Terraform:
```hcl
resource "aws_networkfirewall_logging_configuration" "<example_resource_name>" {
  firewall_arn = "<example_resource_id>"  # 重要: ログ記録を有効にするためにファイアウォールをターゲットにします

  logging_configuration {
    log_destination_config {
      log_type             = "FLOW"              # 重要: 少なくとも1つのログタイプを有効にします
      log_destination_type = "CloudWatchLogs"   # 重要: 有効な送信先タイプを選択します
      log_destination = {
        logGroup = "<example_log_group_name>"   # 重要: ログを受信する既存のCloudWatch Logsグループ
      }
    }
  }
}
```
